# Recommended lambda_fm values by task type
LAMBDA_FM_RECOMMENDATIONS = {
    # Unconditional GAN (DCGAN-like): small lambda, adversarial is primary
    'unconditional': 1.0,

    # Paired image-to-image (Pix2Pix): medium lambda alongside L1
    'pix2pix': 10.0,

    # High-resolution synthesis (pix2pixHD): high lambda, critical for stability
    'high_resolution': 10.0,

    # Super-resolution (SRGAN): also include VGG loss
    'super_resolution': 5.0,
}

# Layer selection guidelines:
# - Early layers (relu_1_2, relu_2_2): low-level texture, color, edges
# - Mid layers (relu_3_3, relu_3_4): object parts, local structure
# - Late layers (relu_4_3, relu_5_3): semantic content, high-level features
# For image-to-image translation: relu_2_2 and relu_3_3 are the best defaults
# For style transfer: add relu_1_2 for fine texture detail

def build_loss_config(task='pix2pix'):
    """Return a loss configuration dict for common tasks."""
    configs = {
        'pix2pix': {
            'lambda_l1': 100.0,
            'lambda_fm_disc': 10.0,   # discriminator feature matching
            'lambda_vgg': 0.0,        # not needed with paired data + L1
            'vgg_layers': None,
        },
        'pix2pixhd': {
            'lambda_l1': 0.0,         # no L1 at high resolution (too heavy)
            'lambda_fm_disc': 10.0,
            'lambda_vgg': 10.0,
            'vgg_layers': ('relu_2_2', 'relu_3_3', 'relu_4_3'),
        },
        'super_resolution': {
            'lambda_l1': 0.0,
            'lambda_fm_disc': 1e-3,   # very small — mostly VGG
            'lambda_vgg': 0.006,      # scaled to pixel loss magnitude
            'vgg_layers': ('relu_2_2', 'relu_5_3'),
        },
    }
    return configs.get(task, configs['pix2pix'])
